/* eslint react/forbid-foreign-prop-types:off */
import { Key } from "../../common/constants/keyboard";
import { sendScore } from "../utils/score";
import { getBounds } from "../utils/bounds";

export const DragNDrop = Component =>
  class extends Component {
    static propTypes = Component.propTypes;

    state = {
      ...this.state,
      complete: false,
      currentItemId: null,
      currentItemIndex: null,
      correctZoneIndexes: [],
      transitionItemIndexes: [],
      activeZoneIndex: null,
      notFocusable: false,
      ariaText: ""
    };

    _dragItems = [];
    dropZones = [];
    zoneOffsets = [];

    get dragItems() {
      this._dragItems = this._dragItems.filter(item => !!item);
      return this._dragItems;
    }

    constructor(...args) {
      super(...args);
      this.onActivityKeyDown = this.onActivityKeyDown.bind(this);
    }

    handleStart = data => {
      if (this.state.transitionItemIndexes.length === 0) {
        const dragItemIndex = data.index;
        const dragItemId = this.props.items[dragItemIndex].id;

        data.item.setDetached(true);
        this.setState({
          currentItemIndex: dragItemIndex,
          currentItemId: dragItemId
        });
      }
    };

    handleDrag = data => {
      let hitZone = false;
      const { inPlayerPos } = data;

      this.zoneOffsets.forEach((item, ind) => {
        if (
          inPlayerPos.x > item.left &&
          inPlayerPos.x < item.right &&
          inPlayerPos.y > item.top &&
          inPlayerPos.y < item.bottom
        ) {
          hitZone = true;
          if (ind !== this.state.activeZoneIndex) {
            this.setState({
              activeZoneIndex: ind
            });
          }
        }
      });

      if (!hitZone && this.state.activeZoneIndex !== null) {
        this.setState({
          activeZoneIndex: null
        });
      }
    };

    handleKeyboardDrop = e => {
      e.preventDefault();
      const { zones } = this.props;
      const dragItemId = this.state.currentItemId;
      const dragItemIndex = this.state.currentItemIndex;
      const dragItemBounds = getBounds(e.target);
      let correctDrop = false;
      let dropZoneIndex;

      this.dropZones.forEach((item, index) => {
        if (
          ((dragItemBounds.right > item.left + item.width / 2 &&
            dragItemBounds.right < item.right) ||
            (dragItemBounds.left < item.left + item.width / 2 &&
              dragItemBounds.left > item.left)) &&
          ((dragItemBounds.bottom > item.top + item.height / 2 &&
            dragItemBounds.bottom < item.bottom) ||
            (dragItemBounds.top < item.top + item.height / 2 && dragItemBounds.top > item.top)) &&
          dragItemId === zones[index].id
        ) {
          correctDrop = true;
          dropZoneIndex = index;
        }
      });

      if (correctDrop) {
        this.dragItems[dragItemIndex].setPosition(
          this.dropZones[dropZoneIndex].left - dragItemBounds.left,
          this.dropZones[dropZoneIndex].top - dragItemBounds.top
        );
        this.handleCorrectDrop(dragItemIndex, dropZoneIndex);
        this.setState({
          currentItemIndex: null,
          currentItemId: null,
          activeZoneIndex: null
        });
        e.target.blur();
      } else {
        this.handleIncorrectDrop(dragItemIndex);
        this.setState({
          activeZoneIndex: null
        });
      }
    };

    handleHotspotDrop = index => {
      const { zones, items, score, activityId, activityType } = this.props;
      const dropZoneId = zones[index].id;
      const dragItemIndex = this.state.currentItemIndex;
      const dragItemId = items[dragItemIndex].id;
      const dragItem = this.dragItems[dragItemIndex];

      if (dropZoneId === dragItemId) {
        const correctZoneIndexes = this.state.correctZoneIndexes.concat(index);
        const correctCount =
          items.filter(
            (item, index) => this.dragItems[index].correct && !this.dragItems[index].mistakes
          ).length + (!this.dragItems[dragItemIndex].mistakes ? 1 : 0);
        const displayedScore = parseFloat((score * (correctCount / items.length)).toFixed(1));

        let complete = this.state.complete;

        dragItem.setDetached(true);
        dragItem.setPosition(this.zoneOffsets[index].left, this.zoneOffsets[index].top);
        dragItem.setCorrect(true);

        if (correctZoneIndexes.length === zones.length) {
          sendScore({
            id: activityId,
            type: activityType,
            pointsEarned: displayedScore,
            maxValue: score,
            isRestart: false
          });

          complete = true;
        }

        this.setState(
          {
            correctZoneIndexes,
            currentItemIndex: null,
            activeZoneIndex: null,
            notFocusable: false,
            displayedScore,
            ariaText: this.locale.correct,
            complete
          },
          () => {
            const remainingItem = document.querySelector(this.remainingItemSelector);

            if (!complete && remainingItem) {
              remainingItem.focus();
            }
          }
        );
      } else {
        dragItem.setCorrect(false);

        this.setState({
          ariaText: this.locale.incorrect
        });
      }
    };

    onDropZoneKeyDown = data => {
      switch (data.keyCode) {
        case Key.ENTER:
          this.handleHotspotDrop(data.index);
          break;
        case Key.TAB:
          if (this.state.ariaText) {
            this.setState({
              ariaText: ""
            });
          }
          break;
        default:
      }
    };

    onTransitionEnd = data => {
      if (!data.item.correct) {
        data.item.setDetached(false);
      }

      this.setState({
        transitionItemIndexes: this.state.transitionItemIndexes.filter(i => i !== data.index)
      });
    };

    onButtonFocus = () => {
      this.setState({
        currentItemIndex: null,
        currentItemId: null
      });
    };

    onDragItemKeyDown = e => {
      const { currentItemIndex, transitionItemIndexes, notFocusable } = this.state;
      const dragItem = this.dragItems[currentItemIndex];

      if (currentItemIndex === null || transitionItemIndexes.length !== 0 || dragItem.disabled) {
        return;
      }

      if (e.keyCode === Key.ENTER && (dragItem.position.x || dragItem.position.y)) {
        this.handleKeyboardDrop(e);
      }

      if (e.keyCode === Key.SPACEBAR) {
        if (!notFocusable) {
          e.preventDefault();
          let firstDropZone = document.querySelector(this.activeDropZoneSelector);

          firstDropZone.focus();
          this.setState({
            notFocusable: true,
            ariaText: this.locale.select
          });
        }
      }
    };

    onDragItemFocus = data => {
      const dragItemId = this.props.items[data.index].id;

      this.setState({
        currentItemIndex: data.index,
        currentItemId: dragItemId
      });
    };

    onActivityKeyDown(e) {
      if (super.onActivityKeyDown) {
        super.onActivityKeyDown(e);
      }

      switch (e.keyCode) {
        case Key.ESC:
          if (this.state.notFocusable) {
            e.preventDefault();
            this.setState({
              notFocusable: false
            });
          }
          break;
        default:
      }
    }
  };
