/* eslint jsx-a11y/aria-role:off */
import styles from "./DropZone.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import { InjectLocale } from "../../../../decorators/locale";
import { isMobile, isTablet, isPhone } from "../../../../../common/constants/user-agent";
import { Classes } from "../../../../../common/constants/classes";
import DropDown from "../DropDown/DropDown";
import Tooltip from "../../../../../common/components/Tooltip/Tooltip";
import { TOOLTIP_CONTAINER } from "../../../../../common/constants/attributes";

@InjectLocale("DropZone")
class DropZone extends PureComponent {
  static propTypes = {
    notFocusable: PropTypes.bool.isRequired,
    complete: PropTypes.bool,
    value: PropTypes.string.isRequired,
    index: PropTypes.number.isRequired,
    id: PropTypes.number.isRequired,
    onCorrectSelect: PropTypes.func,
    onIncorrectSelect: PropTypes.func,
    items: PropTypes.array,
    active: PropTypes.bool,
    correct: PropTypes.bool,
    size: PropTypes.object,
    onKeyDown: PropTypes.func.isRequired,
    top: PropTypes.number,
    left: PropTypes.number,
    altText: PropTypes.string
  };

  dropZoneElement;
  state = {
    displayDropdown: false
  };

  componentDidMount() {
    if (isMobile) {
      this.dropZoneElement.addEventListener("focusout", this.onDropZoneBlur);
    }
  }

  componentDidUpdate() {
    if (isTablet && this.refs.value && !this.fontSize) {
      this.updateValueStyle();
    }
  }

  updateValueStyle() {
    const { value: label } = this.refs;
    const { dropZoneElement: labelValue } = this;
    const value = label.innerText;

    if (labelValue) {
      const { style } = label;

      if (value) {
        const valueWrapperHeight = parseFloat(getComputedStyle(labelValue).height);
        const valueWrapperWidth = parseFloat(getComputedStyle(labelValue).width);

        style.removeProperty("font-size");

        let fontSize = parseFloat(getComputedStyle(labelValue).fontSize);

        style.paddingTop = 0;
        style.paddingBottom = 0;

        while (label.scrollHeight > valueWrapperHeight && fontSize > 0) {
          style.fontSize = `${fontSize}px`;
          fontSize--;
        }
        this.fontSize = fontSize;

        label.style.top = `${(valueWrapperHeight - label.scrollHeight) / 2}px`;
        label.style.left = `${(valueWrapperWidth - label.scrollWidth) / 2}px`;
      } else {
        style.removeProperty("padding-top");
        style.removeProperty("padding-bottom");
        style.removeProperty("height");
        style.removeProperty("font-size");
      }
    }
  }

  componentWillUnmount() {
    if (isMobile) {
      this.dropZoneElement.removeEventListener("focusout", this.onDropZoneBlur);
    }
  }

  hideDropdown = e => {
    const { displayDropdown } = this.state;

    if (displayDropdown && this.dropZoneElement && !this.dropZoneElement.contains(e.target)) {
      this.setState({
        displayDropdown: false
      });
    }
  };

  onDropZoneBlur = e => {
    if (this.dropZoneElement && !this.dropZoneElement.contains(e.relatedTarget)) {
      const { displayDropdown } = this.state;

      if (displayDropdown) {
        this.setState({
          displayDropdown: false
        });
      }
    }
  };

  onClick = () => {
    const { correct, complete } = this.props;

    if (isMobile && !correct && !complete) {
      this.setState({
        displayDropdown: !this.state.displayDropdown
      });
    }
  };

  onKeyDown = e => {
    const { onKeyDown, index } = this.props;

    onKeyDown({
      index,
      keyCode: e.keyCode
    });
  };

  onItemSelect = (itemId, itemIndex) => {
    const { id, index, onCorrectSelect, onIncorrectSelect } = this.props;

    let idx;

    // For select mode use index of drop zone
    if (isPhone() || isTablet()) {
      idx = id;
    }
    // For normal DnD use index of item
    else {
      idx = itemIndex;
    }

    if (id === itemId) {
      onCorrectSelect(idx, index);
    } else {
      onIncorrectSelect(idx);
    }
  };

  get dropZone() {
    const {
      notFocusable,
      complete,
      value,
      active,
      correct,
      top,
      left,
      altText,
      size,
      items,
      index
    } = this.props;
    const { displayDropdown } = this.state;
    const tabIndex = (notFocusable && !correct) || complete ? 0 : -1;
    const { description } = this.locale;
    const ariaLabel = correct ? `${value} ${altText}` : altText;

    return (
      <div
        ref={element => {
          this.dropZoneElement = element;
        }}
        tabIndex={tabIndex}
        role="landmark"
        aria-label={ariaLabel}
        aria-describedby={`${styles.container}${index}__description`}
        aria-dropeffect="move"
        className={classNames(
          styles.container,
          (correct || complete) && styles.correct,
          active && styles.active,
          isPhone() && styles.smallDrop,
          (correct || complete) && isPhone() && styles.mcorrect
        )}
        onKeyDown={this.onKeyDown}
        onTouchEnd={this.onClick}
        style={{
          top: top,
          left: left
        }}
      >
        <span id={`${styles.container}${index}__description`} className={Classes.VISUALLY_HIDDEN}>
          {description}
        </span>
        {isTablet() && <p ref="value">{correct && value}</p>}
        {displayDropdown && (
          <DropDown
            items={items}
            offsetX={0}
            offsetY={size.height + 5}
            onItemClick={this.onItemSelect}
          />
        )}
      </div>
    );
  }

  render() {
    const { correct, index, labelingID, value, showAnswers } = this.props;

    return isMobile && correct && showAnswers ? (
      <Tooltip
        portal={document.getElementById(TOOLTIP_CONTAINER)}
        text={value}
        className={"drop-tooltip"}
        id={"labeling" + labelingID + "drop" + index}
      >
        {this.dropZone}
      </Tooltip>
    ) : (
      this.dropZone
    );
  }
}

export { styles as dropZoneStyles };
export default DropZone;
