import styles from "./DragItem.module.scss";
import React, { PureComponent } from "react";
import ReactDOM from "react-dom";
import PropTypes from "prop-types";
import classNames from "classnames";
import { InjectLocale } from "../../../../decorators/locale";
import { getBounds } from "../../../../utils/bounds";
import { getClientPosition } from "../../../../../common/utils/event";
import { Classes } from "../../../../../common/constants/classes";

@InjectLocale("DragItem")
class DragItem extends PureComponent {
  static minShift = 5;

  static propTypes = {
    index: PropTypes.number.isRequired,
    notFocusable: PropTypes.bool.isRequired,
    active: PropTypes.bool.isRequired,
    transition: PropTypes.bool.isRequired,
    value: PropTypes.string,
    disabled: PropTypes.func.isRequired,
    parentSelector: PropTypes.string,
    size: PropTypes.object,
    onStart: PropTypes.func.isRequired,
    onStop: PropTypes.func.isRequired,
    onDrag: PropTypes.func.isRequired,
    onKeyDown: PropTypes.func.isRequired,
    onFocus: PropTypes.func.isRequired,
    onTransitionEnd: PropTypes.func.isRequired
  };

  dragObject = {};
  isDragging = false;
  fontSize = 16;

  state = {
    correct: false,
    disabled: false,
    mistakes: 0,
    detached: false,
    left: 0,
    top: 0
  };

  componentDidMount() {
    document.addEventListener("mousemove", this.onMouseMove);
    document.addEventListener("mouseup", this.onMouseUp);
    this.parent = document.querySelector(this.props.parentSelector);
    this.updateValueStyle();
  }

  componentWillUnmount() {
    document.removeEventListener("mousemove", this.onMouseMove);
    document.removeEventListener("mouseup", this.onMouseUp);
    this.parent = null;
  }

  onDragStart(e) {
    e.preventDefault();

    return false;
  }

  onMouseDown = e => {
    if (e.nativeEvent.which === 1 && !this.disabled) {
      const bounds = getBounds(e.target);
      const parentBounds = getBounds(this.parent);

      this.dragObject = {
        active: true,
        top: bounds.top,
        left: bounds.left,
        width: bounds.width,
        height: bounds.height,
        parentTop: parentBounds.top,
        parentLeft: parentBounds.left,
        parentWidth: parentBounds.width,
        parentHeight: parentBounds.height,
        clickX: getClientPosition(e).x,
        clickY: getClientPosition(e).y
      };
    }
  };

  onMouseMove = e => {
    e.preventDefault();

    requestAnimationFrame(() => {
      if (this.dragObject.active) {
        const { onStart, onDrag, index } = this.props;

        let clientPos = getClientPosition(e);

        if (!this.isDragging) {
          const shiftX = clientPos.x - this.dragObject.clickX;
          const shiftY = clientPos.y - this.dragObject.clickY;

          if (Math.abs(shiftX) < DragItem.minShift && Math.abs(shiftY) < DragItem.minShift) {
            return;
          }

          const bounds = getBounds(e.target);

          this.dragObject.shiftX = this.dragObject.clickX - bounds.left;
          this.dragObject.shiftY = this.dragObject.clickY - bounds.top;
          this.isDragging = true;
          onStart({
            index,
            bounds,
            item: this
          });
        }

        let left = clientPos.x - this.dragObject.shiftX - this.dragObject.parentLeft;
        let top = clientPos.y - this.dragObject.shiftY - this.dragObject.parentTop;

        left =
          left < 0
            ? 0
            : left + this.dragObject.width > this.dragObject.parentWidth
            ? this.dragObject.parentWidth - this.dragObject.width
            : left;
        top =
          top < 0
            ? 0
            : top + this.dragObject.height > this.dragObject.parentHeight
            ? this.dragObject.parentHeight - this.dragObject.height
            : top;

        onDrag({
          inPlayerPos: {
            x: clientPos.x - this.dragObject.parentLeft,
            y: clientPos.y - this.dragObject.parentTop
          }
        });
        this.setPosition(left, top);
      }
    });
  };

  onMouseUp = e => {
    if (this.dragObject.active) {
      e.preventDefault();
      this.dragObject.active = false;
      if (this.isDragging) {
        this.isDragging = false;
        const clientPos = getClientPosition(e);
        this.props.onStop({
          inPlayerPos: {
            x: clientPos.x - this.dragObject.parentLeft,
            y: clientPos.y - this.dragObject.parentTop
          },
          initialPos: {
            left: this.dragObject.left - this.dragObject.parentLeft,
            top: this.dragObject.top - this.dragObject.parentTop
          }
        });
      }
    }
  };

  onKeyDown = e => {
    this.props.onKeyDown(e);
  };

  onFocus = () => {
    this.props.onFocus({ index: this.props.index });
  };

  onTransitionEnd = () => {
    this.props.onTransitionEnd({
      index: this.props.index,
      item: this
    });
  };

  get position() {
    return {
      x: this.state.left,
      y: this.state.top
    };
  }

  get disabled() {
    return this.state.disabled || this.props.disabled();
  }

  get correct() {
    return this.state.correct;
  }

  get mistakes() {
    return this.state.mistakes;
  }

  setDetached(detached) {
    this.setState({ detached });
  }

  setPosition(left, top) {
    this.setState({ left, top });
  }

  setCorrect(correct, giveUp) {
    this.setState({
      correct,
      disabled: correct ? true : this.state.disabled,
      mistakes: (correct && giveUp) || !correct ? this.state.mistakes + 1 : this.state.mistakes
    });
  }

  updateValueStyle() {
    const { dragContainer: labelValue, value: label } = this.refs;
    const value = label.innerText;

    if (labelValue) {
      const { style } = label;

      if (value) {
        const valueWrapperHeight = parseFloat(getComputedStyle(labelValue).height);
        const valueWrapperWidth = parseFloat(getComputedStyle(labelValue).width);

        style.removeProperty("font-size");

        let fontSize = parseFloat(getComputedStyle(labelValue).fontSize);

        style.paddingTop = 0;
        style.paddingBottom = 0;

        while (label.scrollHeight > valueWrapperHeight && fontSize > 0) {
          style.fontSize = `${fontSize}px`;
          fontSize = fontSize - 0.5;
        }
        this.fontSize = fontSize;

        this.top = (valueWrapperHeight - label.scrollHeight) / 2;
        this.left = (valueWrapperWidth - label.scrollWidth) / 2;
      } else {
        style.removeProperty("padding-top");
        style.removeProperty("padding-bottom");
        style.removeProperty("height");
        style.removeProperty("font-size");
      }
    }
  }

  render() {
    const { notFocusable, active, transition, value, index } = this.props;
    const { correct } = this.state;

    const disabled = this.disabled;
    const tabIndex = notFocusable || disabled ? -1 : 0;
    const { label, description } = this.locale;
    if (!this.state.detached) {
      return (
        <div
          ref="dragContainer"
          tabIndex={tabIndex}
          role="listitem"
          aria-grabbed={false}
          aria-label={`${label} ${value}`}
          aria-describedby={`${styles.container}${index}__description`}
          className={classNames(
            styles.container,
            disabled && styles.disabled,
            active && styles.active,
            transition && styles.transition
          )}
          onKeyDown={this.onKeyDown}
          onFocus={this.onFocus}
          onMouseDown={this.onMouseDown}
          onDragStart={this.onDragStart}
          onTransitionEnd={this.onTransitionEnd}
        >
          <span id={`${styles.container}${index}__description`} className={Classes.VISUALLY_HIDDEN}>
            {description}
          </span>
          <p
            style={{
              top: this.top,
              left: this.left,
              fontSize: this.fontSize + "px"
            }}
            ref="value"
          >
            {value}
          </p>
        </div>
      );
    } else {
      return (
        <>
          {!correct && <div className={styles.placeholder} />}
          {ReactDOM.createPortal(
            <div
              ref="dragContainer"
              style={{
                left: this.state.left,
                top: this.state.top
              }}
              tabIndex={tabIndex}
              role="listitem"
              aria-grabbed={true}
              aria-label={`${label} ${value}`}
              aria-describedby={`${styles.container}${index}__description`}
              className={classNames(
                styles.container,
                styles.dragging,
                disabled && styles.disabled,
                active && styles.active,
                transition && styles.transition
              )}
              onKeyDown={this.onKeyDown}
              onFocus={this.onFocus}
              onMouseDown={this.onMouseDown}
              onDragStart={this.onDragStart}
              onTransitionEnd={this.onTransitionEnd}
            >
              <span
                id={`${styles.container}${index}__description`}
                className={Classes.VISUALLY_HIDDEN}
              >
                {description}
              </span>
              <p
                style={{
                  top: this.top,
                  left: this.left,
                  fontSize: this.fontSize + "px"
                }}
                ref="value"
              >
                {value}
              </p>
            </div>,
            this.parent
          )}
        </>
      );
    }
  }
}

export { styles as dragItemStyles };
export default DragItem;
